def parse_supplier_file(path):
    """Return (producer_id, {product: qty})."""
    base=os.path.basename(path)
    m=re.match(r'day_(\d+)_(PR_\d+)_(.*)', base)
    day=int(m.group(1)); pid=m.group(2); fmt=m.group(3)
    items={}
    if fmt.startswith('api-json'):
        d=json.load(open(path))
        pid=d['supplier_id']
        for it in d['items']:
            items[it['prod_id']]=items.get(it['prod_id'],0)+int(it['delivered_qty'])
    elif fmt.startswith('table-csv'):
        for line in open(path):
            line=line.strip()
            if not line or line.startswith('PRODUCT'): continue
            p,q=line.split(';'); items[p]=items.get(p,0)+int(q)
    elif fmt.startswith('key-value'):
        for line in open(path):
            line=line.strip()
            if line.startswith('PRODUCT'):
                mm=re.search(r'PRODUCT:\s*(P_\d+)\s*\|\s*DELIVERED_QTY:\s*(\d+)',line)
                items[mm.group(1)]=items.get(mm.group(1),0)+int(mm.group(2))
            elif line.startswith('SUPPLIER'):
                mm=re.search(r'SUPPLIER:\s*(PR_\d+)',line); pid=mm.group(1)
    elif fmt.startswith('text-template'):
        for line in open(path):
            mm=re.search(r'Supplier\s+(PR_\d+)\s+delivered\s+(\d+)\s+units of product\s+(P_\d+)',line)
            if mm:
                pid=mm.group(1); items[mm.group(3)]=items.get(mm.group(3),0)+int(mm.group(2))
    return day,pid,items

def parse_order_file(path):
    base=os.path.basename(path)
    m=re.match(r'day_(\d+)_(S_\d+)_(.*)', base)
    day=int(m.group(1)); sid=m.group(2); fmt=m.group(3)
    items={}
