        d=json.load(open(path)); sid=d['store_id']
        for it in d['items']:
            items[it['prod_id']]=items.get(it['prod_id'],0)+int(it['qty'])
    elif fmt.startswith('table-csv'):
        for line in open(path):
            line=line.strip()
            if not line or line.startswith('PRODUCT'): continue
            p,q=line.split(';'); items[p]=items.get(p,0)+int(q)
    elif fmt.startswith('key-value'):
        for line in open(path):
            mm=re.search(r'RECEIVER:\s*(S_\d+)\s*\|\s*ORDER_PRODUCT:\s*(P_\d+)\s*\|\s*ORDER_QTY:\s*(\d+)',line)
            if mm: sid=mm.group(1); items[mm.group(2)]=items.get(mm.group(2),0)+int(mm.group(3))
    elif fmt.startswith('text-template'):
        for line in open(path):
            mm=re.search(r'deliver\s+(\d+)\s+units of product\s+(P_\d+).*Store\s+(S_\d+)',line)
            if mm: items[mm.group(2)]=items.get(mm.group(2),0)+int(mm.group(1)); sid=mm.group(3)
    return day,sid,items

def parse_wh_receipt(path):
    day=pid=seq=None
    for line in open(path):
        line=line.strip()
        if line.startswith('DAY'): day=int(line.split(':')[1])
        elif line.startswith('SUPPLIER_ID'): pid=line.split(':')[1].strip()
        elif line.startswith('DAILY_SEQUENCE_NO'): seq=int(line.split(':')[1])
