        if line.startswith('DAY'): day=int(line.split(':')[1])
        elif line.startswith('STORE_ID'): sid=line.split(':')[1].strip()
        elif line.startswith('DAILY_SEQUENCE_NO'): seq=int(line.split(':')[1])
        elif line.startswith('TOTAL_DELIVERED_UNITS'): tot=int(line.split(':')[1])
    return day,sid,seq,tot

if __name__=='__main__':
    # Day 1 verification
    day=1
