    sup={}  # pid -> {prod:qty}
    for f in glob.glob('raw_supplier_receipts/day_001_*'):
        _,pid,items=parse_supplier_file(f); sup[pid]=items
    # wholesaler seq
    whseq={}
    for f in glob.glob('raw_wholesaler_receipts/day_001_*'):
        _,pid,seq=parse_wh_receipt(f); whseq[pid]=seq
    # build wholesaler per-product FIFO queue in seq order
    order_pids=sorted(sup.keys(), key=lambda p: whseq[p])
    wh_stock=defaultdict(int)
    for pid in order_pids:
        for prod,q in sup[pid].items():
            wh_stock[prod]+=q
    # orders
    orders={}
    for f in glob.glob('raw_orders/day_001_*'):
        _,sid,items=parse_order_file(f); orders[sid]=items
    # store seq + total
    stseq={}; sttot={}
    for f in glob.glob('raw_wholesaler_store_receipts/day_001_*'):
        _,sid,seq,tot=parse_store_receipt(f); stseq[sid]=seq; sttot[sid]=tot
    # brutal fulfillment per product, stores in seq order
    avail=dict(wh_stock)
    store_order_seq=sorted(orders.keys(), key=lambda s: stseq[s])
    delivered=defaultdict(lambda: defaultdict(int))
    for sid in store_order_seq:
        for prod,q in orders[sid].items():
            give=min(q, avail.get(prod,0))
            delivered[sid][prod]+=give
            avail[prod]=avail.get(prod,0)-give
    # compare totals
    print("store_seq order:", store_order_seq)
    print(f"{'store':6} {'recon_total':>12} {'reported_total':>14} match")
    allmatch=True
    for sid in store_order_seq:
        rt=sum(delivered[sid].values())
        ok = rt==sttot[sid]
        allmatch &= ok
        print(f"{sid:6} {rt:12} {sttot[sid]:14} {ok}")
    print("ALL MATCH:", allmatch)
